import{_ as s,C as t,o as h,c,j as a,a as n,E as i,a3 as m}from"./chunks/framework.CVjg771q.js";const q=JSON.parse('{"title":"帛书第9章 知足","description":"帛书德篇第9章 · 知足（通行本第46章）","frontmatter":{"title":"帛书第9章 知足","description":"帛书德篇第9章 · 知足（通行本第46章）","category":"guide","aliases":["帛书第9章","马王堆老子9","通行本第46章"],"source":["马王堆汉墓帛书《老子》甲本"]},"headers":[],"relativePath":"daoism/dao-de-jing-boshu/chapter-09.md","filePath":"daoism/dao-de-jing-boshu/chapter-09.md","lastUpdated":1780591578000}'),p={name:"daoism/dao-de-jing-boshu/chapter-09.md"};function u(x,e,b,g,_,f){const o=t("DaoReadingPrelude"),r=t("DaoOriginalReading"),d=t("DaoLineGuide"),l=t("DaoKeywordCards");return h(),c("div",null,[e[0]||(e[0]=a("h1",{id:"帛书老子第9章",tabindex:"-1"},[n("帛书老子第9章 "),a("a",{class:"header-anchor",href:"#帛书老子第9章","aria-label":'Permalink to "帛书老子第9章"'},"​")],-1)),i(o,{title:"第9章 知足",summary:"本章出自马王堆帛书《老子》甲本德篇，对应通行本第46章。帛书本德篇在前、道篇在后，文字多作「亓」「恒」「邦」等古字，反映了更早的写本面貌。",points:[{label:"底本",text:"马王堆帛书甲本 · 德篇第9章"},{label:"对照",text:"通行本第46章，注意篇序与文字差异"},{label:"读法",text:"初读先顺原文；再读可对照通行本逐句比对异同。"}],hint:'帛书甲本是现存最早的《老子》完整写本之一。文中括号注如「泊（薄）」表示帛书作"泊"，校读为"薄"。'}),e[1]||(e[1]=a("h2",{id:"【原典层】原文",tabindex:"-1"},[n("【原典层】原文 "),a("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),i(r,{paragraphs:["天下有道 却走马以粪","天下无道 戎马生于郊","罪莫大于可欲","祸莫大于不知足","咎莫憯于欲得","故知足之足 恒足矣"]}),i(d,{lines:[{text:"天下有道 却走马以粪",tone:"起",guide:"天下有道的时候，战马退下来用于耕田施肥——太平盛世，兵器化为农具。"},{text:"天下无道 戎马生于郊",tone:"承",guide:"天下无道的时候，战马在城郊产驹——连怀孕的母马都要上战场，可见战乱之惨烈。"},{text:"罪莫大于可欲",tone:"断",guide:"最大的罪过莫过于放纵欲望——可欲即放任欲望无限制地膨胀。"},{text:"祸莫大于不知足",tone:"断",guide:"最大的祸患莫过于不知满足——不知足是万祸之源。"},{text:"咎莫憯于欲得",tone:"断",guide:"最惨痛的过失莫过于贪得无厌——帛书「憯」即惨痛。三句话层层递进：可欲→不知足→欲得。"},{text:"故知足之足 恒足矣",tone:"收",guide:"所以知道满足的那种满足，才是恒久的满足——帛书「恒足」对比通行本「常足」，更加有力。"}]}),e[2]||(e[2]=a("h2",{id:"【原典层】字词释义",tabindex:"-1"},[n("【原典层】字词释义 "),a("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),i(l,{items:[{term:"却",pinyin:["què"],meaning:"退。却走马以粪——把战马退下来用于耕田施肥。却即退却、回归之意。",context:"「却走马」与「戎马生于郊」形成太平与战乱的强烈对比。"},{term:"戎马",pinyin:["róng","mǎ"],meaning:"战马。戎马生于郊——战马在城外产驹，说明连怀孕的母马都被征用，战争之残酷达到极点。",context:"老子以此画面表达对战争的痛心疾首。"},{term:"憯",pinyin:["cǎn"],meaning:"通「惨」——惨痛。咎莫憯于欲得——最惨痛的过失莫过于贪得。",context:"帛书用「憯」，加重了语气——不是一般的过错，而是惨痛之咎。"},{term:"恒足",pinyin:["héng","zú"],meaning:"恒久的满足。帛书作「恒足」，通行本避讳改「常足」。知足之足，恒足矣——知道满足，才是真正的永远满足。",context:"「恒」与「常」之别，见帛书本之古奥。"}]}),e[3]||(e[3]=m('<h2 id="【解读层】三问解读" tabindex="-1">【解读层】三问解读 <a class="header-anchor" href="#【解读层】三问解读" aria-label="Permalink to &quot;【解读层】三问解读&quot;">​</a></h2><h3 id="象-这一章在说什么" tabindex="-1">象：这一章在说什么 <a class="header-anchor" href="#象-这一章在说什么" aria-label="Permalink to &quot;象：这一章在说什么&quot;">​</a></h3><p>本章标题为「知足」，帛书此章围绕「却走马以粪」展开。帛书甲本以古字「亓」「恒」「邦」「靓」等呈现了比通行本更早的文本面貌，读者在阅读时需要注意这些古字的含义及与通行本的对应关系。</p><h3 id="理-为什么这样说" tabindex="-1">理：为什么这样说 <a class="header-anchor" href="#理-为什么这样说" aria-label="Permalink to &quot;理：为什么这样说&quot;">​</a></h3><p>本章在帛书《老子》中的重要性体现在：其一，文本上保留了战国至汉初的古字写法，是考证《老子》流传演变的重要实物；其二，义理上与通行本基本一致但用字更古，某些关键概念（如恒vs常、邦vs国）的差异反映了思想史的重要变化；其三，作为现存最早的《老子》完整写本之一，每章都是理解老子原始思想的珍贵窗口。</p><h3 id="用-这一章今天怎么用" tabindex="-1">用：这一章今天怎么用 <a class="header-anchor" href="#用-这一章今天怎么用" aria-label="Permalink to &quot;用：这一章今天怎么用&quot;">​</a></h3><p>今天读这一章，建议分两步。第一步，先顺读原文，感受帛书古朴的文字气息。第二步，对照通行本对应章节（括号中标注），体会异文带来的理解差异。帛书本提醒我们：经典文本从来不是凝固不变的——每一次抄写，都可能是一次微小的诠释。这种对文本流动性的感知，本身就是一种珍贵的学习体验。</p><h2 id="【解读层】现代重述" tabindex="-1">【解读层】现代重述 <a class="header-anchor" href="#【解读层】现代重述" aria-label="Permalink to &quot;【解读层】现代重述&quot;">​</a></h2><p>待整理。</p><h2 id="【解读层】我的理解" tabindex="-1">【解读层】我的理解 <a class="header-anchor" href="#【解读层】我的理解" aria-label="Permalink to &quot;【解读层】我的理解&quot;">​</a></h2><p>待整理。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>马王堆汉墓帛书《老子》甲本（底本）</li><li>对应通行本第46章，所属帛书德篇</li><li>高明《帛书老子校注》</li><li>国家文物局古文献研究室《马王堆汉墓帛书（壹）》</li></ul>',13))])}const k=s(p,[["render",u]]);export{q as __pageData,k as default};
